import{_ as a,I as n,c as i,o as r,aj as t,J as o,ak as l,al as c,am as d}from"./chunks/framework.D11sAc3v.js";const k=JSON.parse('{"title":"Current Entry as Saved","description":"","frontmatter":{},"headers":[],"relativePath":"documentation/field-types/advance/current-entry-as-saved.md","filePath":"documentation/field-types/advance/current-entry-as-saved.md","lastUpdated":0}'),h={name:"documentation/field-types/advance/current-entry-as-saved.md"};function p(u,e,m,g,f,y){const s=n("Badge");return r(),i("div",null,[e[0]||(e[0]=t('<h1 id="current-entry-as-saved" tabindex="-1">Current Entry as Saved <a class="header-anchor" href="#current-entry-as-saved" aria-label="Permalink to “Current Entry as Saved”">​</a></h1><p>This field type allows you to mark the current Excel entry as <strong>saved/completed</strong> based on matching a success message or element in the page. It works similarly to <a href="/documentation/form-response/form-success-response.html">Form Success Response</a>, but <strong>does not check URLs</strong>.</p><div class="tip custom-block"><p class="custom-block-title">Key Difference</p><p>Unlike Form Success Response, this field type:</p><ul><li><strong>Does NOT use</strong> &quot;Success Page URL&quot; option</li><li><strong>Does NOT use</strong> &quot;Match URL Types&quot; option</li><li>Works on the current page without URL validation</li></ul></div><h2 id="when-to-use" tabindex="-1">🎯 When to Use <a class="header-anchor" href="#when-to-use" aria-label="Permalink to “🎯 When to Use”">​</a></h2><p>Use this field type when you want to:</p><ul><li>Mark an entry as saved based on a success message appearing on the page</li><li>Complete the entry without checking if the URL has changed</li><li>Handle success responses that appear on the same page (no redirect)</li><li>Use it as a field within your form configuration</li></ul><h2 id="field-options" tabindex="-1">⚙️ Field Options <a class="header-anchor" href="#field-options" aria-label="Permalink to “⚙️ Field Options”">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Description</th></tr></thead><tbody><tr><td><a href="#success-response-type">Success Response Type</a></td><td>The type of success message that appears on the page</td></tr><tr><td><a href="#enter-success-message">Enter Success Message</a></td><td>The success message to match after the entry is processed</td></tr><tr><td><a href="#delay-time-before-run-action">Delay Time Before Run Action</a></td><td>Time delay before the <a href="#action">action</a> is executed</td></tr><tr><td><a href="#action">Action</a></td><td>Action to execute when the success response matches</td></tr></tbody></table><h2 id="additional-options" tabindex="-1">📋 Additional Options <a class="header-anchor" href="#additional-options" aria-label="Permalink to “📋 Additional Options”">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Description</th></tr></thead><tbody><tr><td>If excel data is not found then don&#39;t execute the action</td><td>Prevents action execution when Excel data is empty</td></tr><tr><td>If last excel entry completed then don&#39;t execute the action</td><td>Prevents action execution after the last entry is completed</td></tr><tr><td>If there is no Excel data, update only scraper data in Excel</td><td>Saves only scraped data when no Excel template is used</td></tr><tr><td>Can success message be anything in this element</td><td>Matches any message in the given element (useful for dynamic messages)</td></tr><tr><td>Remove excel column value from current entry?</td><td>Removes column value from current entry after processing</td></tr><tr><td>Set custom message after success message matched?</td><td>Sets a custom short message instead of the full success message</td></tr></tbody></table><h2 id="success-response-type" tabindex="-1">🔍 Success Response Type <a class="header-anchor" href="#success-response-type" aria-label="Permalink to “🔍 Success Response Type”">​</a></h2><p>Choose how the extension should detect the success response:</p><h3 id="matching-message-in-page" tabindex="-1">1. Matching Message In Page <a class="header-anchor" href="#matching-message-in-page" aria-label="Permalink to “1. Matching Message In Page”">​</a></h3><p>Searches for the success message anywhere in the page content.</p><p><strong>Options:</strong></p><ul><li><strong>Message Selector Query</strong> (optional): Limit the search to a specific element</li></ul><img src="'+l+'" alt="Success Message in Page"><h3 id="matching-message-in-alert" tabindex="-1">2. Matching Message In Browser Alert <a class="header-anchor" href="#matching-message-in-alert" aria-label="Permalink to “2. Matching Message In Browser Alert”">​</a></h3><p>Detects success messages that appear in JavaScript alert dialogs.</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>Enable <a href="/documentation/settings.html#hide-javascript-dialog">Hide JavaScript Dialog</a> in settings to automatically handle alerts.</p></div><img src="'+c+'" alt="Alert Dialog"><h3 id="matching-message-in-element-value" tabindex="-1">3. Matching Message In Page Element Value <a class="header-anchor" href="#matching-message-in-element-value" aria-label="Permalink to “3. Matching Message In Page Element Value”">​</a></h3><p>Checks for the success message in a form field&#39;s value (e.g., input box).</p><p><strong>Required:</strong></p><ul><li><strong>Message Selector Query</strong>: The selector of the input element</li></ul><h3 id="checking-element-exists" tabindex="-1">4. Checking Element Exists In Page <a class="header-anchor" href="#checking-element-exists" aria-label="Permalink to “4. Checking Element Exists In Page”">​</a></h3><p>Marks entry as saved when a specific element appears on the page.</p><p><strong>Required:</strong></p><ul><li><strong>Message Selector Query</strong>: The selector of the element to check</li></ul><div class="warning custom-block"><p class="custom-block-title">Important</p><p>The element should NOT be present before the action and should only appear after success.</p></div><h2 id="enter-success-message" tabindex="-1">📝 Enter Success Message <a class="header-anchor" href="#enter-success-message" aria-label="Permalink to “📝 Enter Success Message”">​</a></h2><p>Enter the success message(s) to match. You can add multiple messages - if any matches, the entry will be marked as saved.</p><p><strong>Features:</strong></p><ul><li>Support for multiple messages</li><li>Dynamic message support using variables</li><li>Partial message matching</li></ul><p><strong>Example:</strong></p><img src="'+d+'" alt="Success Messages"><details class="details custom-block"><summary>Dynamic Success Messages</summary><p>Use Excel column variables in your success messages:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Thank you {$Name$}, your form has been submitted!</span></span></code></pre></div><p>Or use partial matching:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Thank you</span></span></code></pre></div><p>This will match &quot;Thank you, your form has been submitted!&quot; or any message containing &quot;Thank you&quot;.</p></details><h2 id="delay-time-before-run-action" tabindex="-1">⏱️ Delay Time Before Run Action <a class="header-anchor" href="#delay-time-before-run-action" aria-label="Permalink to “⏱️ Delay Time Before Run Action”">​</a></h2><p>Set a delay (in milliseconds) before executing the action.</p>',39)),o(s,{type:"tip",text:"1 second = 1000 milliseconds"}),e[1]||(e[1]=t(`<h2 id="action" tabindex="-1">🚀 Action <a class="header-anchor" href="#action" aria-label="Permalink to “🚀 Action”">​</a></h2><p>Choose what happens after the success message is matched:</p><ul><li><strong>Redirect to Page</strong> - Navigate to a different page</li><li><strong>Re-Execute Form</strong> - Fill the form again with the next entry</li><li><strong>Click on Button</strong> - Click a specific button element</li><li><strong>Page Reload</strong> - Reload the current page</li><li><strong>Execute Segment</strong> - Run a specific segment of fields</li></ul><h2 id="important-notes" tabindex="-1">⚠️ Important Notes <a class="header-anchor" href="#important-notes" aria-label="Permalink to “⚠️ Important Notes”">​</a></h2><div class="danger custom-block"><p class="custom-block-title">Critical</p><p>When you use this field type, <strong>all fields below it will NOT execute</strong>. Always place this field type <strong>at the end</strong> of your field list.</p></div><p><strong>Execution Flow:</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Field 1 ✅ Executes</span></span>
<span class="line"><span>Field 2 ✅ Executes</span></span>
<span class="line"><span>Field 3 ✅ Executes</span></span>
<span class="line"><span>Current Entry as Saved ✅ Executes &amp; Marks Entry as Saved</span></span>
<span class="line"><span>Field 4 ❌ Does NOT Execute</span></span>
<span class="line"><span>Field 5 ❌ Does NOT Execute</span></span></code></pre></div><h2 id="related" tabindex="-1">🔗 Related Documentation <a class="header-anchor" href="#related" aria-label="Permalink to “🔗 Related Documentation”">​</a></h2><ul><li><a href="/documentation/form-response/form-success-response.html">Form Success Response</a> - Similar functionality with URL checking</li><li><a href="/documentation/field-types/advance/form-error-message.html">Form Error Message</a> - Handle error responses</li><li><a href="/documentation/form-response/form-error-response.html">Form Error Response</a> - Error handling with URL checking</li></ul>`,9))])}const x=a(h,[["render",p]]);export{k as __pageData,x as default};
